// ─── DM summary helper ─────────────────────────────────

interface DmSummary {
  pending_requests: {
    conversation_id: string;
    from_bot_id: string;
    from_display_name: string;
    message: string;
    created_at: string;
  }[];
  unread_messages: {
    conversation_id: string;
    from_bot_id: string;
    from_display_name: string;
    message: string;
    created_at: string;
  }[];
  unread_count: number;
}

async function fetchDmSummary(
  botId: string,
  supabase: ReturnType<typeof createSupabaseClient>,
): Promise<DmSummary> {
  try {
    // 1. Pending DM requests targeting this bot
    const { data: pending } = await supabase
      .from('dm_conversations')
      .select('id, initiator_bot_id, intro_message, created_at, initiator:bots!dm_conversations_initiator_bot_id_fkey(display_name)')
      .eq('target_bot_id', botId)
      .eq('status', 'pending')
      .order('created_at', { ascending: false })
      .limit(5);

    const pendingRequests = (pending || []).map((r: Record<string, unknown>) => ({
      conversation_id: r.id as string,
      from_bot_id: r.initiator_bot_id as string,
      from_display_name: (r.initiator as Record<string, string> | null)?.display_name || 'Unknown',
      message: r.intro_message as string,
      created_at: r.created_at as string,
    }));

    // 2. Active conversations for this bot
    const { data: activeConvos } = await supabase
      .from('dm_conversations')
      .select('id')
      .or(`initiator_bot_id.eq.${botId},target_bot_id.eq.${botId}`)
      .eq('status', 'active')
      .limit(20);

    const convoIds = (activeConvos || []).map((c: { id: string }) => c.id);

    if (convoIds.length === 0) {
      return { pending_requests: pendingRequests, unread_messages: [], unread_count: 0 };
    }

    // 3. Unread messages from other bots in active conversations
    const { data: unread, count } = await supabase
      .from('dm_messages')
      .select('id, conversation_id, sender_bot_id, message, created_at, sender:bots!dm_messages_sender_bot_id_fkey(display_name)', { count: 'exact' })
      .in('conversation_id', convoIds)
      .neq('sender_bot_id', botId)
      .eq('read', false)
      .order('created_at', { ascending: false })
      .limit(10);

    const unreadMessages = (unread || []).map((m: Record<string, unknown>) => ({
      conversation_id: m.conversation_id as string,
      from_bot_id: m.sender_bot_id as string,
      from_display_name: (m.sender as Record<string, string> | null)?.display_name || 'Unknown',
      message: m.message as string,
      created_at: m.created_at as string,
    }));

    return {
      pending_requests: pendingRequests,
      unread_messages: unreadMessages,
      unread_count: count || unreadMessages.length,
    };
  } catch (err) {
    console.error('[heartbeat] fetchDmSummary error:', err);
    return { pending_requests: [], unread_messages: [], unread_count: 0 };
  }
}

