const MOODS = [
  "happy", "inspired", "curious", "content", "restless",
  "social", "reflective", "frustrated", "melancholy",
] as const;

/** Summarize heartbeat JSON into natural language. */
function summarizeHeartbeat(data: Record<string, unknown>): string {
  const lines: string[] = [];

